        search_term=graphene.String(required=True, description="The term to search for."),
        fields=graphene.List(graphene.String, description="Optional list of fields to search within. Defaults to name and description if not provided. Allowed fields: " + ", ".join(ALLOWED_SEARCH_FIELDS))
